type UpdateModuleShareParams struct {
	ID         pgtype.UUID        `json:"id"`
	CanView    *bool              `json:"can_view"`
	CanInstall *bool              `json:"can_install"`
	CanModify  *bool              `json:"can_modify"`
	CanReshare *bool              `json:"can_reshare"`
	ExpiresAt  pgtype.Timestamptz `json:"expires_at"`
}

func (q *Queries) UpdateModuleShare(ctx context.Context, arg UpdateModuleShareParams) (ModuleShare, error) {
	row := q.db.QueryRow(ctx, updateModuleShare,
		arg.ID,
		arg.CanView,
		arg.CanInstall,
		arg.CanModify,
		arg.CanReshare,
		arg.ExpiresAt,
	)
	var i ModuleShare
	err := row.Scan(
		&i.ID,
		&i.ModuleID,
		&i.SharedWithUserID,
		&i.SharedWithWorkspaceID,
		&i.SharedWithEmail,
		&i.CanView,
		&i.CanInstall,
		&i.CanModify,
		&i.CanReshare,
		&i.SharedBy,
		&i.SharedAt,
		&i.ExpiresAt,
	)
	return i, err
}
